  {
    "lang": "hi",
    "category": "wait",
    "text": "\u0906\u092a \u092c\u0947\u0938\u092c\u094d\u0930 \u0928\u0939\u0940\u0902 \u0939\u0948\u0902\u0964 \u0906\u092a \u092c\u0938 \u0932\u0902\u091a \u092e\u0947\u0902 \u092d\u093e\u0935\u0928\u093e\u0924\u094d\u092e\u0915 \u0930\u0942\u092a \u0938\u0947 \u0928\u093f\u0935\u0947\u0936 \u0915\u0930 \u091a\u0941\u0915\u0947 \u0939\u0948\u0902\u0964"
  },
  {
    "lang": "hi",
    "category": "food",
    "text": "\u0905\u091a\u094d\u091b\u0947 \u0916\u093e\u0928\u0947 \u0915\u094b \u092d\u093e\u0937\u0923 \u0928\u0939\u0940\u0902 \u091a\u093e\u0939\u093f\u090f, \u092c\u0938 \u092a\u0939\u0932\u093e \u0936\u093e\u0902\u0924 \u092c\u093e\u0907\u091f \u091a\u093e\u0939\u093f\u090f\u0964"
  },
  {
    "lang": "hi",
    "category": "dad",
    "text": "\u0905\u091a\u093e\u0930 \u0907\u0924\u0928\u093e \u0936\u093e\u0902\u0924 \u0915\u094d\u092f\u094b\u0902 \u0925\u093e? \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0935\u0939 \u092a\u0939\u0932\u0947 \u0938\u0947 \u0939\u0940 \u091c\u093e\u0930 \u092e\u0947\u0902 \u0938\u0947\u091f\u0932 \u0925\u093e\u0964"
  },
  {
    "lang": "hi",
    "category": "desi",
    "text": "\u0915\u094b\u0908 \u0915\u0939\u0924\u093e \u0939\u0948 \u092c\u0938 \u090f\u0915 \u092c\u093e\u0907\u091f, \u0914\u0930 \u092a\u094d\u0932\u0947\u091f \u0906\u0927\u0940 \u092c\u0939\u0941\u0924 \u0907\u091c\u093c\u094d\u091c\u093c\u0924 \u0938\u0947 \u0917\u093e\u092f\u092c \u0939\u094b \u091c\u093e\u0924\u0940 \u0939\u0948\u0964"
  },
  {
    "lang": "hi",
    "category": "wait",
    "text": "\u092a\u0947\u091f \u0915\u093e \u092e\u0948\u0938\u0947\u091c \u0906\u092f\u093e \u0939\u0948: \u0915\u094b\u0908 \u092a\u094d\u0930\u0947\u0936\u0930 \u0928\u0939\u0940\u0902, \u092c\u0938 \u091c\u0932\u094d\u0926\u0940 \u0915\u0930 \u0926\u094b\u0964"
  }
